const payload = $json.body ?? $json;
const notification = payload.notification ?? payload;
const notificationId = String(notification.notificationId ?? '').trim();
const callbackUrl = String(notification.callbackUrl ?? '').trim();
const recipient = String(notification.recipient ?? '').trim();
const channel = String(notification.channel ?? 'EMAIL').trim().toUpperCase();
const body = typeof notification.body === 'string' ? notification.body : '';
if (!notificationId) {
  throw new Error('Missing notificationId.');
}
if (!callbackUrl) {
  throw new Error('Missing callbackUrl.');
}
if (!recipient) {
  throw new Error('Missing recipient.');
}
return [{ json: { event: payload.event ?? null, occurredAt: payload.occurredAt ?? null, notificationId, callbackUrl, callbackSecret: typeof notification.callbackSecret === 'string' ? notification.callbackSecret : null, recipient, channel, subject: typeof notification.subject === 'string' ? notification.subject : null, body, providerMessageId: `n8n-${channel.toLowerCase()}-${Date.now()}`, receivedAt: new Date().toISOString() } }];
